// Extraer los datos del webhook de Evolution API
const body = $input.first().json.body || $input.first().json;

// Filtrar solo eventos de nuevos mensajes
if (body.event !== 'messages.upsert') {
  return []; // Ignorar otros eventos (como status, acks)
}

const messageData = body.data;

// Ignorar mensajes enviados por el propio bot (para evitar bucles)
if (!messageData || !messageData.key || messageData.key.fromMe) {
  return [];
}

// Obtener el número de teléfono (removiendo el sufijo @s.whatsapp.net)
const remoteJid = messageData.key.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '');

// Obtener el nombre del perfil de WhatsApp
const name = messageData.pushName || 'Cliente';

// Extraer el texto del mensaje (puede venir en 'conversation' o 'extendedTextMessage')
let text = '';
if (messageData.message) {
  text = messageData.message.conversation || 
         (messageData.message.extendedTextMessage && messageData.message.extendedTextMessage.text) || 
         '';
}

// Si no hay texto, ignorar (puede ser una imagen sin caption)
if (!text) return [];

return [{
  json: {
    phone: phone,
    name: name,
    message: text,
    sessionId: phone // Usaremos el teléfono como ID de memoria para el agente
  }
}];
